func solve(nums: Array<Int64>) -> Int64 {
    let n = nums.count()
    if n == 0 {
        return 0
    }
    let totalSize = 1 << n
    var log2 = Array<Int64>(repeating: -1, count: totalSize)
    for i in 0..<n {
        let power = Int64(1 << i)
        log2[power] = Int64(i)
    }

    var totalXOR = Array<Int64>(repeating: 0, count: totalSize)
    for mask in 1..<totalSize {
        let lowbit = mask & -mask
        let idx = log2[Int64(lowbit)]
        totalXOR[mask] = totalXOR[mask & ~lowbit] ^ nums[Int(idx)]
    }

    var and_total = Array<Int64>(repeating: 0, count: totalSize)
    for mask in 0..<totalSize {
        if mask == 0 {
            and_total[mask] = 0
        } else {
            var and_val: Int64 = -1
            for i in 0..<n {
                if (mask >> i) & 1 != 0 {
                    and_val = and_val & nums[i]
                }
            }
            and_total[mask] = and_val
        }
    }

    var F = Array<Int64>(repeating: 0, count: totalSize)
    for mask in 0..<totalSize {
        F[mask] = totalXOR[mask]
        var submask = mask
        while submask != 0 {
            let x = totalXOR[submask]
            let candidate = x + (totalXOR[mask] ^ x)
            if candidate > F[mask] {
                F[mask] = candidate
            }
            submask = (submask - 1) & mask
        }
    }

    let full_mask = totalSize - 1
    var ans: Int64 = 0
    for B_mask in 0..<totalSize {
        let R_mask = full_mask ^ B_mask
        let s = and_total[B_mask] + F[R_mask]
        if s > ans {
            ans = s
        }
    }

    return ans
}
```

