        int j = idx_for_power[low];
        and_mask[mask] = and_mask[mask - low] & nums[j];
    }

    Int64 global_max = 0;
    long long total_mask_val = (1LL << n) - 1;
    for (int mask_B = 0; mask_B < total_mask_count; mask_B++) {
        long long R = total_mask_val ^ mask_B;
        Int64 and_B = (mask_B == 0) ? 0 : and_mask[mask_B];
        if (R == 0) {
            if (and_B > global_max) {
                global_max = and_B;
            }
        } else {
            Int64 xor_R = xor_mask[R];
            Int64 best_val = 0;
            long long mask_A = R;
            while (true) {
