import Foundation

func solve(nums: Array<Int64>) -> Int64 {
    let n = nums.count
    guard n > 0 else {
        return 0
    }
    var total_xor_all: Int64 = 0
    for num in nums {
        total_xor_all ^= num
    }
    let total_mask = 1 << n
    var best: Int64 = Int64.min

    for mask in 0..<total_mask {
        var andB_temp: Int64 = -1
        var xorB_temp: Int64 = 0
        var arr = [Int64]()
        var hasB = false

        for i in 0..<n {
            if mask & (1 << i) != 0 {
                andB_temp = andB_temp & nums[i]
                xorB_temp = xorB_temp ^ nums[i]
                hasB = true
            } else {
                arr.append(nums[i])
            }
        }
        if !hasB {
            andB_temp = 0
        }

        let T_val = total_xor_all ^ xorB_temp
        let m = arr.count

        if m == 0 {
            let total_val = andB_temp
            if total_val > best {
                best = total_val
            }
        } else {
            let total_subsets = 1 << m
            var xs = Array(repeating: Int64(0), count: total_subsets)
            var bestForR: Int64 = Int64.min
            xs[0] = 0
            bestForR = max(bestForR, 0 + (T_val ^ 0))

            for i in 0..<m {
                let step = 1 << i
                for j in step..<(step << 1) {
                    let prev = j ^ step
                    xs[j] = xs[prev] ^ arr[i]
                    let expr = xs[j] + (T_val ^ xs[j])
                    if expr > bestForR {
                        bestForR = expr
                    }
                }
            }
            let total_val = andB_temp + bestForR
            if total_val > best {
                best = total_val
            }
        }
    }
    return best
}
```

